#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to search for a value in the BST
int searchInBST(Node* root, int x) {
    if (root == NULL) {
        return 0;
    }
    if (root->val == x) {
        return 1;
    }
    if (root->val < x) {
        return searchInBST(root->right, x);
    } else {
        return searchInBST(root->left, x);
    }
}

int main() {
    int N, X;
    scanf("%d %d", &N, &X);
    Node* root = NULL;
    for (int i = 0; i < N - 1; i++) {
        int pi, ci;
        char Ri;
        scanf("%d %d %c", &pi, &ci, &Ri);
        // Create nodes and assign them to the tree
        Node* parentNode = NULL;
        Node* childNode = createNode(ci);
        if (root == NULL) {
            root = createNode(pi);
            parentNode = root;
        } else {
            Node* temp = root;
            while (temp != NULL) {
                if (temp->val == pi) {
                    parentNode = temp;
                    break;
                }
                if (temp->val < pi) {
                    if (temp->right == NULL) {
                        temp->right = createNode(pi);
                        parentNode = temp->right;
                        break;
                    }
                    temp = temp->right;
                } else {
                    if (temp->left == NULL) {
                        temp->left = createNode(pi);
                        parentNode = temp->left;
                        break;
                    }
                    temp = temp->left;
                }
            }
        }
        if (Ri == 'L') {
            parentNode->left = childNode;
        } else {
            parentNode->right = childNode;
        }
    }
    if (searchInBST(root, X)) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }
    return 0;
}

